    97→void ReadBuffer::BackUp(int count)
    98→{
    99→    SCHECK_GT(_last_bytes, 0);
   100→    SCHECK_GE(count, 0);
   101→    SCHECK_LE(count, _last_bytes);
   102→    if (count > 0)
   103→    {
