   112→bool ReadBuffer::Skip(int count)
   113→{
   114→    SCHECK_GE(count, 0);
   115→    const void* data;
   116→    int size;
   117→    while (count > 0 && Next(&data, &size))
   118→    {
   119→        if (size > count)
   120→        {
   121→            BackUp(size - count);
   122→            size = count;
   123→        }
   124→        count -= size;
   125→    }
   126→    _last_bytes = 0;
   127→    return count == 0;
