   163→    while (!_buf_list.empty())
   164→    {
   165→        BufHandle& buf_handle = _buf_list.front();
   166→        if (buf_handle.size > 0)
   167→        {
   168→            buf_handle.offset = 0; // capacity -> offset
   169→            is->Append(buf_handle);
