   181→    SCHECK_GT(count, 0);
   182→    int64 head = ByteCount();
   183→    void* data;
   184→    int size;
   185→    while (count > 0)
   186→    {
   187→        if (!Next(&data, &size))
   188→            return -1;
   189→        if (size > count)
   190→        {
   191→            BackUp(size - count);
