   207→    BufHandleListIterator cur_it = _buf_list.begin();
   208→    int cur_offset = 0;
   209→    while (pos > 0)
   210→    {
   211→        SCHECK(cur_it != _buf_list.end());
   212→        int cur_size = cur_it->size - cur_offset;
   213→        if (cur_size > pos)
   214→        {
   215→            cur_offset += pos;
   216→            pos = 0;
   217→        }
   218→        else
   219→        {
