   244→bool WriteBuffer::Next(void** data, int* size)
   245→{
   246→    BufHandleListReverseIterator last = _buf_list.rbegin();
   247→    if (last == _buf_list.rend() || last->size == last->capacity)
   248→    {
   249→        if (!Extend())
   250→        {
   251→            _last_bytes = 0;
   252→            return false;
   253→        }
   254→        last = _buf_list.rbegin();
   255→    }
   256→    *data = last->data + last->size;
   257→    *size = last->capacity - last->size;
   258→    last->size = last->capacity;
   259→    _last_bytes = *size;
   260→    _write_bytes += _last_bytes;
   261→    return true;
